export type BootstrapPhase = 'COLD_PASS' | 'CANONICALIZATION' | 'WARM_PASS' | 'DASHBOARD' | 'COMPLETE';
export type SystemState = 'BOOTSTRAP_COLD' | 'BOOTSTRAP_WARMING' | 'STEADY_STATE';

const PHASE_ORDER: BootstrapPhase[] = ['COLD_PASS', 'CANONICALIZATION', 'WARM_PASS', 'DASHBOARD', 'COMPLETE'];

const PHASE_TO_STATE: Record<BootstrapPhase, SystemState> = {
  COLD_PASS: 'BOOTSTRAP_COLD',
  CANONICALIZATION: 'BOOTSTRAP_COLD',
  WARM_PASS: 'BOOTSTRAP_WARMING',
  DASHBOARD: 'BOOTSTRAP_WARMING',
  COMPLETE: 'STEADY_STATE',
};

export class BootstrapOrchestrator {
  private _currentPhase: BootstrapPhase = 'COLD_PASS';

  get currentPhase(): BootstrapPhase {
    return this._currentPhase;
  }

  get systemState(): SystemState {
    return PHASE_TO_STATE[this._currentPhase];
  }

  runPhase(): BootstrapPhase {
    const currentIndex = PHASE_ORDER.indexOf(this._currentPhase);
    if (currentIndex < PHASE_ORDER.length - 1) {
      this._currentPhase = PHASE_ORDER[currentIndex + 1];
    }
    return this._currentPhase;
  }

  isComplete(): boolean {
    return this._currentPhase === 'COMPLETE';
  }
}

export function createBootstrapOrchestrator(): BootstrapOrchestrator {
  return new BootstrapOrchestrator();
}

